import{_ as a,o as i,c as o,a2 as r}from"./chunks/framework.DCVnL8g5.js";const b=JSON.parse('{"title":"Registry, despliegue y observabilidad","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/nifi/06-registry-despliegue-y-observabilidad.md","filePath":"data-engineering/nifi/06-registry-despliegue-y-observabilidad.md","lastUpdated":1782521464000}'),l={name:"data-engineering/nifi/06-registry-despliegue-y-observabilidad.md"};function s(n,e,t,d,c,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="registry-despliegue-y-observabilidad" tabindex="-1">Registry, despliegue y observabilidad <a class="header-anchor" href="#registry-despliegue-y-observabilidad" aria-label="Permalink to &quot;Registry, despliegue y observabilidad&quot;">​</a></h1><p>NiFi Registry permite versionar flujos y promover cambios entre entornos con mas control. Junto con parametros y observabilidad, convierte NiFi en una pieza operable en produccion.</p><h2 id="nifi-registry" tabindex="-1">NiFi Registry <a class="header-anchor" href="#nifi-registry" aria-label="Permalink to &quot;NiFi Registry&quot;">​</a></h2><p>NiFi Registry guarda versiones de process groups.</p><p>Permite:</p><ul><li>Versionar cambios.</li><li>Comparar versiones.</li><li>Revertir.</li><li>Promocionar flujos.</li><li>Revisar historial.</li></ul><p>Flujo recomendado:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dev -&gt; commit en Registry -&gt; test -&gt; import/update en prod</span></span></code></pre></div><h2 id="versionado-de-process-groups" tabindex="-1">Versionado de process groups <a class="header-anchor" href="#versionado-de-process-groups" aria-label="Permalink to &quot;Versionado de process groups&quot;">​</a></h2><p>Versiona grupos con una responsabilidad clara. Si versionas todo el canvas como una unica unidad, cada cambio pequeno afectara a demasiadas piezas.</p><p>Buenas practicas:</p><ul><li>Un grupo versionado por pipeline o dominio.</li><li>Mensajes de cambio claros.</li><li>Cambios pequenos y revisables.</li><li>Parametros fuera del flujo versionado cuando dependan del entorno.</li></ul><h2 id="promocion-entre-entornos" tabindex="-1">Promocion entre entornos <a class="header-anchor" href="#promocion-entre-entornos" aria-label="Permalink to &quot;Promocion entre entornos&quot;">​</a></h2><p>Para mover un flujo de dev a prod:</p><ol><li>Versiona el process group en Registry.</li><li>Revisa cambios.</li><li>Asegura que los parameter contexts existen en destino.</li><li>Valida controller services.</li><li>Despliega en entorno de pruebas.</li><li>Arranca de forma controlada.</li><li>Observa colas y errores.</li></ol><h2 id="despliegue-seguro" tabindex="-1">Despliegue seguro <a class="header-anchor" href="#despliegue-seguro" aria-label="Permalink to &quot;Despliegue seguro&quot;">​</a></h2><p>Antes de cambiar produccion:</p><ul><li>Deten entradas si el cambio afecta a ingesta.</li><li>Deja drenar colas si es necesario.</li><li>Haz snapshot/version del flujo anterior.</li><li>Verifica parametros.</li><li>Revisa relaciones nuevas.</li><li>Comprueba permisos y controller services.</li><li>Define plan de rollback.</li></ul><h2 id="observabilidad-en-nifi" tabindex="-1">Observabilidad en NiFi <a class="header-anchor" href="#observabilidad-en-nifi" aria-label="Permalink to &quot;Observabilidad en NiFi&quot;">​</a></h2><p>NiFi ofrece varias fuentes de observabilidad:</p><ul><li>Estado de processors.</li><li>Colas.</li><li>Bulletins.</li><li>Logs.</li><li>Provenance.</li><li>Estado del cluster.</li><li>Metricas expuestas por la plataforma.</li></ul><h2 id="data-provenance" tabindex="-1">Data Provenance <a class="header-anchor" href="#data-provenance" aria-label="Permalink to &quot;Data Provenance&quot;">​</a></h2><p>Data Provenance muestra el historial de un FlowFile:</p><ul><li>Donde se creo.</li><li>Que processors lo tocaron.</li><li>Que atributos cambiaron.</li><li>A donde se envio.</li><li>En que momento ocurrio cada evento.</li></ul><p>Es una herramienta clave para depurar y auditar.</p><h2 id="bulletins" tabindex="-1">Bulletins <a class="header-anchor" href="#bulletins" aria-label="Permalink to &quot;Bulletins&quot;">​</a></h2><p>Los bulletins son avisos visibles en la interfaz. Suelen indicar errores de processors, problemas de configuracion o fallos de servicios.</p><p>No sustituyen a una estrategia de alertas externa, pero ayudan a operar desde el canvas.</p><h2 id="alertas-recomendadas" tabindex="-1">Alertas recomendadas <a class="header-anchor" href="#alertas-recomendadas" aria-label="Permalink to &quot;Alertas recomendadas&quot;">​</a></h2><ul><li>Cola por encima de umbral.</li><li>Processor con errores repetidos.</li><li>Disco de repositorios alto.</li><li>Nodo desconectado.</li><li>Controller service caido.</li><li>Flujo sin procesar datos cuando deberia.</li><li>Dead letter creciendo.</li></ul><h2 id="backups" tabindex="-1">Backups <a class="header-anchor" href="#backups" aria-label="Permalink to &quot;Backups&quot;">​</a></h2><p>En produccion, conserva:</p><ul><li>Configuracion de NiFi.</li><li>Flujos versionados.</li><li>Parameter contexts.</li><li>Certificados.</li><li>Configuracion de seguridad.</li><li>Plantillas o exportaciones si aun se usan.</li></ul><p>Registry no reemplaza todos los backups del entorno.</p><h2 id="checklist-operativo" tabindex="-1">Checklist operativo <a class="header-anchor" href="#checklist-operativo" aria-label="Permalink to &quot;Checklist operativo&quot;">​</a></h2><ul><li>Flujos versionados en Registry.</li><li>Parametros separados por entorno.</li><li>Controller services validados.</li><li>Alertas de colas, errores y disco.</li><li>Provenance con retencion adecuada.</li><li>Runbook de despliegue y rollback.</li><li>Backups probados.</li><li>Cambios documentados.</li></ul>',36)])])}const m=a(l,[["render",s]]);export{b as __pageData,m as default};
